mapper.select:
SELECT
    d.*,
    b.kb_name AS kb_name
FROM kb_document d
LEFT JOIN kb_base b ON d.kb_id = b.kb_id AND b.del_flag = '0'
WHERE d.del_flag = '0'

    AND d.doc_id = #{bo.docId}


    AND d.tenant_id = #{bo.tenantId}


    AND d.kb_id = #{bo.kbId}


    AND b.kb_name LIKE CONCAT('%', #{bo.kbName}, '%')


    AND d.file_id = #{bo.fileId}


    AND d.file_name LIKE CONCAT('%', #{bo.fileName}, '%')


    AND d.file_type = #{bo.fileType}


    AND d.file_size = #{bo.fileSize}


    AND d.file_url LIKE CONCAT('%', #{bo.fileUrl}, '%')


    AND d.object_key = #{bo.objectKey}


    AND d.title LIKE CONCAT('%', #{bo.title}, '%')


    AND d.source_type = #{bo.sourceType}


    AND d.source_url LIKE CONCAT('%', #{bo.sourceUrl}, '%')


    AND d.parse_status = #{bo.parseStatus}


    AND d.embed_status = #{bo.embedStatus}


    AND d.chunk_count = #{bo.chunkCount}


    AND d.token_count = #{bo.tokenCount}


    AND d.char_count = #{bo.charCount}


    AND d.content_hash = #{bo.contentHash}


    AND d.error_message LIKE CONCAT('%', #{bo.errorMessage}, '%')


    AND d.status = #{bo.status}


    AND d.create_by = #{bo.createBy}


    AND d.create_time = #{bo.createTime}


    AND d.update_by = #{bo.updateBy}


    AND d.update_time = #{bo.updateTime}
